const projeto = $('Limit — 1 projeto').item.json;
const conteudos = $input.all().map(i => i.json).filter(c => c.agente === 'copywriter' || !c.agente);

return [{
  json: {
    projeto_id: projeto.id,
    brief: projeto.brief || '',
    plano: projeto.plano,
    data_sugerida: (projeto.plano && projeto.plano.resultado && projeto.plano.resultado.data_sugerida_publicacao) || null,
    conteudos_copy: conteudos.map(c => ({
      id: c.id,
      tipo: c.tipo,
      conteudo: c.conteudo
    }))
  }
}];

const projetoId = $('Code — prompt Social IG').item.json.projeto_id;
const dataSugerida = $('Code — prompt Social IG').item.json.data_sugerida;
const resp = $input.first().json;

const text = (resp.content || [])
  .filter(b => b.type === 'text')
  .map(b => b.text)
  .join('\n')
  .trim();

let parsed;
try {
  const cleaned = text.replace(/^```json\s*/i, '').replace(/```$/i, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    projeto_id: projetoId,
    agente: 'social_media',
    status: 'erro',
    resultado: { publicacoes: [] },
    qualidade: 0,
    problemas: ['JSON inválido: ' + e.message, text.slice(0, 500)],
    proximo_agente: null
  };
}

parsed.projeto_id = parsed.projeto_id || projetoId;
parsed.agente = 'social_media';

const raw = String(parsed.status || '').toLowerCase().trim();
const okAliases = new Set(['ok', 'completo', 'complete', 'success', 'sucesso', 'done']);
if (okAliases.has(raw)) parsed.status = 'ok';
else if (['precisa_revisao', 'revisao', 'review'].includes(raw)) parsed.status = 'precisa_revisao';
else if (['erro', 'error', 'fail', 'failed'].includes(raw)) parsed.status = 'erro';
else if (parsed.resultado && Array.isArray(parsed.resultado.publicacoes) && parsed.resultado.publicacoes.length) {
  parsed.status = 'ok';
} else {
  parsed.status = 'erro';
}

if (parsed.qualidade && typeof parsed.qualidade === 'object') {
  const n = Number(parsed.qualidade.nota);
  parsed.qualidade = Number.isFinite(n) ? Math.round(n * (n <= 10 ? 10 : 1)) : 0;
}

// força instagram
const pubs = ((parsed.resultado && parsed.resultado.publicacoes) || []).map(p => ({
  ...p,
  plataforma: 'instagram'
}));
if (!parsed.resultado) parsed.resultado = {};
parsed.resultado.publicacoes = pubs;

const estado = parsed.status === 'ok' ? 'adaptado' : 'erro';

return [{
  json: {
    projeto_id: projetoId,
    data_sugerida: dataSugerida,
    estado,
    saida: parsed,
    publicacoes: pubs,
    status_agente: parsed.status,
    mensagem_log: parsed.status === 'ok'
      ? ('Social Media IG: ' + pubs.length + ' versão(ões)')
      : ('Social Media: ' + parsed.status)
  }
}];

const base = $input.first().json;
const rows = [];

if (base.status_agente === 'ok' && base.publicacoes.length) {
  for (const p of base.publicacoes) {
    rows.push({
      json: {
        insert_mode: 'conteudo',
        projeto_id: base.projeto_id,
        data_sugerida: base.data_sugerida,
        estado: base.estado,
        status_agente: base.status_agente,
        mensagem_log: base.mensagem_log,
        tipo: p.formato || 'post_instagram',
        conteudo: p
      }
    });
    rows.push({
      json: {
        insert_mode: 'publicacao',
        projeto_id: base.projeto_id,
        data_sugerida: base.data_sugerida,
        estado: base.estado,
        status_agente: base.status_agente,
        mensagem_log: base.mensagem_log,
        plataforma: 'instagram',
        pub: p
      }
    });
  }
}

rows.push({
  json: {
    insert_mode: 'finalizar',
    projeto_id: base.projeto_id,
    data_sugerida: base.data_sugerida,
    estado: base.estado,
    status_agente: base.status_agente,
    mensagem_log: base.mensagem_log
  }
});

return rows;
